class BaseAnalyzer(ABC):
    """분석기 기본 클래스"""

    def __init__(self, name: str):
        self.name = name
        self.results = []

    @abstractmethod
    async def analyze(self, data: Any) -> Dict[str, Any]:
        """분석 수행"""
        pass

    def get_results(self) -> List[Dict[str, Any]]:
        """결과 반환"""
        return self.results

