def calculate_complexity(symbols: List[Dict[str, Any]]) -> int:
    """복잡도 계산"""
    return len(symbols) * 2 + 10

def format_analysis_result(result: Dict[str, Any]) -> str:
    """분석 결과 포맷팅"""
    return json.dumps(result, indent=2, ensure_ascii=False)
